// İndeks imzalarının sintaksisi
interface Dictionary {
  [key: string]: number;
}

let scores: Dictionary = {
  math: 90,
  science: 85
};

console.log(scores); // { math: 90, science: 85 }
scores.history = 88; // Keçərlidir
console.log(scores); // { math: 90, science: 85, history: 88 }
// scores.math = '90'; // Xəta: string tipi number tipinə uyğun deyil

// String və number indeks imzaları
interface StringMap {
  [key: string]: string;
}

interface NumberMap {
  [index: number]: string;
}

let stringMap: StringMap = {
  name: 'Ali',
  city: 'Baku'
};

let numberMap: NumberMap = {
  0: 'zero',
  1: 'one'
};

console.log(stringMap); // { name: 'Ali', city: 'Baku' }
console.log(numberMap); // { 0: 'zero', 1: 'one' }
stringMap.country = 'Azerbaijan'; // Keçərlidir
numberMap[2] = 'two'; // Keçərlidir
// stringMap.age = 25; // Xəta: number tipi string tipinə uyğun deyil

// İndeks imzaları ilə tip aliasları
type StringDictionary = {
  [key: string]: string;
};

interface NumberDictionary {
  [key: number]: number;
}

let stringDict: StringDictionary = { name: 'Ali', role: 'Developer' };
let numberDict: NumberDictionary = { 1: 100, 2: 200 };

console.log(stringDict); // { name: 'Ali', role: 'Developer' }
console.log(numberDict); // { 1: 100, 2: 200 }
stringDict.status = 'Active'; // Keçərlidir
numberDict[3] = 300; // Keçərlidir
// stringDict.age = 25; // Xəta: number tipi string tipinə uyğun deyil

// Readonly indeks imzaları
interface ReadonlyDictionary {
  readonly [key: string]: string;
}

let dict: ReadonlyDictionary = {
  name: 'Ali',
  city: 'Baku'
};

console.log(dict); // { name: 'Ali', city: 'Baku' }
// dict.name = 'Vəli'; // Xəta: name yalnız oxuna biləndir
// dict.country = 'Azerbaijan'; // Xəta: country yalnız oxuna biləndir

// İndeks imzaları ilə optional xüsusiyyətlər
interface User {
  name: string;
  [key: string]: string | number;
}

let user: User = {
  name: 'Ali',
  age: 25,
  city: 'Baku'
};

console.log(user); // { name: 'Ali', age: 25, city: 'Baku' }
user.country = 'Azerbaijan'; // Keçərlidir
// user.status = true; // Xəta: boolean tipi string və ya number tipinə uyğun deyil

// Funksiyalarda indeks imzaları
interface Settings {
  [key: string]: string;
}

function printSettings(settings: Settings): string {
  let result = '';
  for (const key in settings) {
    result += `${key}: ${settings[key]}, `;
  }
  return result;
}

let settings: Settings = { theme: 'dark', language: 'en' };
console.log(printSettings(settings)); // theme: dark, language: en, 
settings.font = 'Arial'; // Keçərlidir
console.log(printSettings(settings)); // theme: dark, language: en, font: Arial,

// Praktik nümunə
interface ProductAttributes {
  [key: string]: string | number;
}

function displayProductAttributes(attrs: ProductAttributes): string {
  let result = '';
  for (const key in attrs) {
    result += `${key}: ${attrs[key]}, `;
  }
  return result;
}

let product: ProductAttributes = {
  name: 'Phone',
  price: 1000,
  brand: 'BrandX'
};

console.log(displayProductAttributes(product)); // name: Phone, price: 1000, brand: BrandX, 
product.color = 'Black'; // Keçərlidir
console.log(displayProductAttributes(product)); // name: Phone, price: 1000, brand: BrandX, color: Black,

// Təhlükəsizlik nümunəsi
interface UserData {
  [key: string]: string;
}

function getUserData(data: UserData, key: string): string {
  return data[key] ?? 'Unknown';
}

let user: UserData = { name: 'Ali', role: 'Developer' };
console.log(getUserData(user, 'name')); // Ali
console.log(getUserData(user, 'role')); // Developer
// user.age = 25; // Xəta: number tipi string tipinə uyğun deyil

// Səhvə yol açan nümunə
let unsafe: any = { name: 'Ali', age: 25 };
console.log(unsafe.name, unsafe.age); // Ali, 25, lakin tip təhlükəsizliyi yoxdur
unsafe.status = true; // Keçərlidir, lakin təhlükəsiz deyil

// Düzgün yol
interface SafeDictionary {
  [key: string]: string | number;
}

let safe: SafeDictionary = { name: 'Ali', age: 25 };
console.log(safe.name, safe.age); // Ali, 25
safe.city = 'Baku'; // Keçərlidir
// safe.status = true; // Xəta: boolean tipi string və ya number tipinə uyğun deyil

// Real layihə ssenarisi
interface ApiResponse {
  id: number;
  [key: string]: string | number;
}

function processApiResponse(response: ApiResponse): string {
  let result = `ID: ${response.id}`;
  for (const key in response) {
    if (key !== 'id') {
      result += `, ${key}: ${response[key]}`;
    }
  }
  return result;
}

let response: ApiResponse = {
  id: 1,
  name: 'ProductX',
  price: 1000,
  category: 'Electronics'
};

console.log(processApiResponse(response)); // ID: 1, name: ProductX, price: 1000, category: Electronics
response.brand = 'BrandY'; // Keçərlidir
console.log(processApiResponse(response)); // ID: 1, name: ProductX, price: 1000, category: Electronics, brand: BrandY

